// Parse the agent's JSON output and consolidate the investor id and parsed payload
// into a single item that downstream nodes can reliably reference via $json.
const raw = $input.first().json.output ?? $input.first().json.text ?? '';
const loopItem = $('Loop Each Investor').item.json;
const investorId = loopItem.id;
const investorName = loopItem.name;

let parsed;
try {
  const cleaned = raw.replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: {
    investor_id: investorId,
    name: investorName,
    parse_ok: false,
    error: 'Agent output was not valid JSON: ' + String(e.message).slice(0, 500),
    raw: String(raw).slice(0, 2000)
  }}];
}

const validPlatforms = new Set(['twitter','linkedin','instagram','facebook']);
const socials = Array.isArray(parsed.socials)
  ? parsed.socials.filter(s => s && validPlatforms.has(s.platform) && s.url)
  : [];

return [{ json: {
  investor_id: investorId,
  name: investorName,
  parse_ok: true,
  website: parsed.website || null,
  website_source: parsed.website_source || null,
  aum_usd: (typeof parsed.aum_usd === 'number' && isFinite(parsed.aum_usd)) ? parsed.aum_usd : null,
  aum_source: parsed.aum_source || null,
  firm_type: parsed.firm_type || null,
  headquarters: parsed.headquarters || null,
  focus_sectors: Array.isArray(parsed.focus_sectors) ? parsed.focus_sectors.map(String) : [],
  socials,
  confidence: parsed.confidence || 'low',
  notes: parsed.notes || ''
}}];

// Build a single safe SQL UPDATE for the investor row.
// We escape strings by doubling single quotes and reject any non-allowlisted firm_type / confidence value.
function sqlStr(v) { return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'"; }
function sqlNum(v) { return (typeof v === 'number' && isFinite(v)) ? String(v) : 'NULL'; }
function sqlEnum(v, allowed, fallback) {
  if (!v) return fallback ? "'" + fallback + "'" : 'NULL';
  return allowed.includes(v) ? "'" + v + "'" : (fallback ? "'" + fallback + "'" : 'NULL');
}
function sqlJsonb(arr) {
  const safe = Array.isArray(arr) ? arr.map(String) : [];
  return "'" + JSON.stringify(safe).replace(/'/g, "''") + "'::jsonb";
}

const d = $json;
const sql = `UPDATE investors
SET website = COALESCE(${sqlStr(d.website)}, website),
    aum_usd = COALESCE(${sqlNum(d.aum_usd)}, aum_usd),
    firm_type = COALESCE(${sqlEnum(d.firm_type, ['VC','Angel','Family Office','PE','CVC'], null)}, firm_type),
    headquarters = COALESCE(${sqlStr(d.headquarters)}, headquarters),
    focus_sectors = ${sqlJsonb(d.focus_sectors)},
    enrichment_confidence = ${sqlEnum(d.confidence, ['high','medium','low'], 'low')},
    enrichment_notes = ${sqlStr(d.notes)},
    enrichment_status = 'enriched',
    enrichment_completed_at = NOW()
WHERE id = ${sqlStr(d.investor_id)}
RETURNING id;`;

return [{ json: { sql, investor_id: d.investor_id, socials: d.socials, parsed: d } }];

// Pull the socials forward from Parse Agent Output (Postgres UPDATE doesn't pass them through).
const parsed = $('Parse Agent Output').item.json;
const investorId = parsed.investor_id;
const socials = parsed.socials || [];
if (socials.length === 0) return [];

function sqlStr(v) { return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'"; }
const allowed = new Set(['twitter','linkedin','instagram','facebook']);

return socials
  .filter(s => s && allowed.has(s.platform) && s.url)
  .map(s => {
    const sql = `INSERT INTO investor_socials (investor_id, platform, url, handle, source, last_checked_at)
VALUES (${sqlStr(investorId)}, ${sqlStr(s.platform)}, ${sqlStr(s.url)}, ${sqlStr(s.handle || null)}, ${sqlStr(s.source || null)}, NOW())
ON CONFLICT (investor_id, platform) DO UPDATE
SET url = EXCLUDED.url,
    handle = EXCLUDED.handle,
    source = EXCLUDED.source,
    last_checked_at = NOW();`;
    return { json: { sql, investor_id: investorId, platform: s.platform } };
  });

